# Utility module with helper functions and static utilities
# Tests import of functions across modules

const VERSION: str = "1.0.0"

def compute_checksum(data: list[int]) -> int:
    """Simple checksum function"""
    total: int = 0
    for val in data:
        total = total + val
    return total % 256

def format_coords(x: float, y: float) -> str:
    return "(" + str(x) + ", " + str(y) + ")"

class Formatter:
    @static
    def format_priority(p: int) -> str:
        result: str = "Unknown"
        if p == 1:
            result = "Low"
        elif p == 2:
            result = "Medium"
        elif p == 3:
            result = "High"
        return result
